package com.assetflow.nexora.entity;
import jakarta.persistence.*; import java.time.*; @Entity @Table(name="activity_logs") public class ActivityLog { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="log_id") public Long id; @Column(name="user_id") public Long userId; @Column(nullable=false,length=100) public String action; @Column(name="entity_type",nullable=false,length=50) public String entityType; @Column(name="entity_id",nullable=false) public Long entityId; @Column(columnDefinition="jsonb") public String details; @Column(name="ip_address",length=45) public String ipAddress; @Column(name="created_at",nullable=false) public OffsetDateTime createdAt; @PrePersist void created(){if(createdAt==null)createdAt=OffsetDateTime.now(ZoneOffset.UTC);} }
